// Parse incoming message from Evolution API
const body = $input.first().json.body || $input.first().json;

// Extract message data
const data = body.data || body;
const instance = body.instance || '';
const event = body.event || 'messages.upsert';

// Process messages.upsert (incoming) and send.message (secretary from phone)
if (event !== 'messages.upsert' && event !== 'send.message') {
  return [{ json: { skip: true, reason: 'not a message event' } }];
}

// send.message = could be secretary from phone or Lara via API
if (event === 'send.message') {
  const source = data.source || '';
  // Skip if sent by API (Lara) — only process if from phone (android/web/ios)
  if (source === 'unknown' || source === '' || source === 'api') {
    return [{ json: { skip: true, reason: 'send.message from API (Lara)' } }];
  }
  const sendPhone = (data.remoteJid || data.key?.remoteJid || '').replace('@s.whatsapp.net', '').replace(/@.*/, '');
  const sendText = data.message?.conversation || data.message?.extendedTextMessage?.text || '';
  const sendJid = data.remoteJid || data.key?.remoteJid || '';
  if (sendText) {
    return [{ json: { skip: false, phone: sendPhone, text: sendText, contentType: 'secretary_reply', caption: '', mediaType: '', pushName: '', messageId: data.key?.id || '', remoteJid: sendJid, instance: instance, timestamp: new Date().toISOString() } }];
  }
  return [{ json: { skip: true, reason: 'send.message without text' } }];
}

const msg = data.message || data;
const key = data.key || {};

// Detect outgoing messages from phone (secretary replied manually)
if (key.fromMe) {
  // Extract recipient phone - try multiple sources
  let recipientPhone = '';
  if (key.remoteJid && key.remoteJid.includes('@s.whatsapp.net')) {
    recipientPhone = key.remoteJid.replace('@s.whatsapp.net', '');
  } else if (key.senderPn) {
    recipientPhone = key.senderPn.replace('@s.whatsapp.net', '');
  } else if (data.pushName && key.remoteJid) {
    // LID format - try to find phone from participant
    recipientPhone = (key.participant || key.remoteJid || '').replace(/@.*/, '');
  }
  const outText = msg.conversation || msg.extendedTextMessage?.text || '';
  // Flag as secretary reply if has text
  if (outText) {
    return [{ json: { skip: false, phone: recipientPhone || '', text: outText, contentType: 'secretary_reply', caption: '', mediaType: '', pushName: '', messageId: key.id || '', remoteJid: key.remoteJid || '', instance: instance, timestamp: new Date().toISOString() } }];
  }
  return [{ json: { skip: true, reason: 'outgoing message without text' } }];
}

// GUARD: Skip group messages
if (key.remoteJid && (key.remoteJid.includes('@g.us') || key.remoteJid.includes('@broadcast'))) {
  return [{ json: { skip: true, reason: 'group or broadcast message' } }];
}

// Extract phone: prefer senderPn (LID format), fallback to remoteJid
let phone = '';
if (key.senderPn) {
  phone = key.senderPn.replace('@s.whatsapp.net', '');
} else if (key.remoteJid && key.remoteJid.includes('@s.whatsapp.net')) {
  phone = key.remoteJid.replace('@s.whatsapp.net', '');
} else if (body.sender) {
  phone = body.sender.replace('@s.whatsapp.net', '');
} else {
  phone = (key.remoteJid || '').replace(/@.*/, '');
}

const messageId = key.id || '';
const pushName = data.pushName || msg.pushName || '';
const remoteJid = key.remoteJid || '';

// Detect content type
let contentType = 'text';
let text = msg.conversation || msg.extendedTextMessage?.text || '';
let caption = '';
let mediaType = '';

if (msg.imageMessage) {
  contentType = 'image';
  caption = msg.imageMessage.caption || '';
  text = caption || '[imagem recebida]';
  mediaType = msg.imageMessage.mimetype || 'image/jpeg';
} else if (msg.audioMessage) {
  contentType = 'audio';
  text = '[audio recebido]';
  mediaType = msg.audioMessage.mimetype || 'audio/ogg';
} else if (msg.videoMessage) {
  contentType = 'video';
  caption = msg.videoMessage.caption || '';
  text = caption || '[video recebido]';
  mediaType = msg.videoMessage.mimetype || 'video/mp4';
} else if (msg.documentMessage) {
  contentType = 'document';
  text = '[documento recebido: ' + (msg.documentMessage.fileName || 'arquivo') + ']';
  mediaType = msg.documentMessage.mimetype || '';
} else if (msg.stickerMessage) {
  contentType = 'sticker';
  text = '[sticker recebido]';
}

if (!phone) {
  return [{ json: { skip: true, reason: 'no phone' } }];
}

// GUARD: Truncar mensagens muito longas (economia de tokens)
if (text.length > 2000) {
  text = text.substring(0, 2000) + '... [mensagem truncada]';
}

return [{
  json: {
    skip: false,
    phone: phone,
    text: text,
    contentType: contentType,
    caption: caption,
    mediaType: mediaType,
    pushName: pushName,
    messageId: messageId,
    remoteJid: remoteJid,
    instance: instance,
    timestamp: new Date().toISOString()
  }
}];

// Download media from Evolution API if needed
const parseData = $('Parse Message').first().json;
const ctxData = $input.first().json;

const contentType = parseData.contentType || 'text';
let mediaBase64 = null;
let mediaContentType = null;

if (contentType === 'image' || contentType === 'audio') {
  try {
    const result = await this.helpers.httpRequest({
      method: 'POST',
      url: 'http://n8n_evolution-api:8080/chat/getBase64FromMediaMessage/Mih',
      headers: {
        'apikey': '429683C4C977415CAAFCCE10F7D57E11',
        'Content-Type': 'application/json'
      },
      body: {
        message: {
          key: {
            remoteJid: parseData.remoteJid,
            id: parseData.messageId,
            fromMe: false
          }
        }
      },
      json: true
    });
    if (result && result.base64) {
      const b64 = result.base64;
      const commaIdx = b64.indexOf(',');
      mediaBase64 = commaIdx >= 0 ? b64.substring(commaIdx + 1) : b64;
      mediaContentType = parseData.mediaType || (contentType === 'image' ? 'image/jpeg' : 'audio/ogg');
    }
  } catch (e) {
    // Media download failed, continue without it
  }
}

return [{
  json: {
    ...ctxData,
    mediaBase64: mediaBase64,
    mediaContentType: mediaContentType,
    contentType: contentType,
    audioTranscript: null
  }
}];

// Extract Claude response and detect tags
const claudeRes = $input.first().json;
const prevData = $('Build Claude Prompt').first().json;
const parseData = $('Parse Message').first().json;

const aiResponse = claudeRes.content?.[0]?.text || 'Desculpe, tive um problema. Pode repetir?';
const tokensUsed = (claudeRes.usage?.input_tokens || 0) + (claudeRes.usage?.output_tokens || 0);

// Detect conversation tags from AI response
const tags = [];
const lower = aiResponse.toLowerCase();
if (lower.includes('horário') || lower.includes('agendar') || lower.includes('marcar')) tags.push('pronto_agendar');
if (lower.includes('vou confirmar com a dra')) tags.push('precisa_humano');

// Detect from user message
const userMsg = prevData.messageText.toLowerCase();
if (userMsg.includes('preço') || userMsg.includes('valor') || userMsg.includes('quanto custa')) tags.push('perguntou_preco');
if (userMsg.includes('caro') || userMsg.includes('não tenho')) tags.push('objecao_preco');
if (userMsg.includes('reclamaç') || userMsg.includes('insatisf') || userMsg.includes('problema')) tags.push('precisa_humano');

// Detect patient name from user message
// Common patterns: "meu nome é X", "sou o/a X", "me chamo X", "é a/o X"
let detectedName = null;
const namePatterns = [
  /(?:meu nome [eé]|me chamo|sou (?:o|a|eu)?\s*)\s+([A-ZÀ-Ú][a-zà-ú]+(?:\s+[A-ZÀ-Ú][a-zà-ú]+)*)/i,
  /^(?:(?:oi|ol[aá]|bom dia|boa (?:tarde|noite)),?\s*)?(?:(?:sou|aqui [eé])\s+(?:o|a)?\s*)([A-ZÀ-Ú][a-zà-ú]+)/i
];
for (const pattern of namePatterns) {
  const match = prevData.messageText.match(pattern);
  if (match && match[1]) {
    detectedName = match[1].trim();
    break;
  }
}

// Use pushName as fallback if no lead name exists
const leadName = detectedName || (prevData.leadId ? null : parseData.pushName) || null;

// Detect [FOTO:queixa] tag in AI response
let photoQueixa = null;
let cleanResponse = aiResponse;
const fotoMatch = aiResponse.match(/\[FOTO:([^\]]+)\]/);
if (fotoMatch) {
  photoQueixa = fotoMatch[1].trim();
  cleanResponse = aiResponse.replace(/\[FOTO:[^\]]+\]/g, '').replace(/\n{3,}/g, '\n\n').trim();
}

return [{
  json: {
    phone: prevData.phone,
    leadId: prevData.leadId,
    conversationId: prevData.conversationId,
    aiResponse: cleanResponse,
    tokensUsed: tokensUsed,
    tags: tags,
    persona: prevData.persona,
    instance: prevData.instance,
    userMessage: prevData.messageText,
    detectedName: leadName,
    photoQueixa: photoQueixa
  }
}];

// Send photo if [FOTO:queixa] was detected
const data = $('Process AI Response').first().json;
const photoQueixa = data.photoQueixa;

if (!photoQueixa) {
  return [{ json: { photoSent: false } }];
}

try {
  // Fetch ALL photos from bank
  const allMedia = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://oqboitkpcvuaudouwvkl.supabase.co/rest/v1/rpc/wa_get_media',
    headers: {
      'apikey': 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Im9xYm9pdGtwY3Z1YXVkb3V3dmtsIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzQ0NTgyMzQsImV4cCI6MjA5MDAzNDIzNH0.8d1HT8GTxIVsaTtl9eOiijDkWUVDLaTv2W4qahmI8w0',
      'Authorization': 'Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Im9xYm9pdGtwY3Z1YXVkb3V3dmtsIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzQ0NTgyMzQsImV4cCI6MjA5MDAzNDIzNH0.8d1HT8GTxIVsaTtl9eOiijDkWUVDLaTv2W4qahmI8w0',
      'Content-Type': 'application/json'
    },
    body: {},
    json: true
  });

  if (!allMedia || allMedia.length === 0) {
    return [{ json: { photoSent: false, queixa: photoQueixa } }];
  }

  // Get previously sent photos in this conversation
  let sentUrls = [];
  if (data.conversationId) {
    try {
      const convData = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://oqboitkpcvuaudouwvkl.supabase.co/rest/v1/rpc/wa_inbox_conversation',
        headers: {
          'apikey': 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Im9xYm9pdGtwY3Z1YXVkb3V3dmtsIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzQ0NTgyMzQsImV4cCI6MjA5MDAzNDIzNH0.8d1HT8GTxIVsaTtl9eOiijDkWUVDLaTv2W4qahmI8w0',
          'Authorization': 'Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Im9xYm9pdGtwY3Z1YXVkb3V3dmtsIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzQ0NTgyMzQsImV4cCI6MjA5MDAzNDIzNH0.8d1HT8GTxIVsaTtl9eOiijDkWUVDLaTv2W4qahmI8w0',
          'Content-Type': 'application/json'
        },
        body: { p_conversation_id: data.conversationId },
        json: true
      });
      const msgs = convData?.messages || [];
      sentUrls = msgs.filter(m => m.content && m.content.includes('Resultado real')).map(m => m.content);
    } catch(e) {}
  }

  // Filter: prefer matching queixa, exclude already sent
  let candidates = allMedia.filter(m => m.queixas && m.queixas.includes(photoQueixa) && !sentUrls.some(s => s.includes(m.filename)));

  // Fallback: any photo not yet sent
  if (candidates.length === 0) {
    candidates = allMedia.filter(m => !sentUrls.some(s => s.includes(m.filename)));
  }

  // Last fallback: any photo
  if (candidates.length === 0) {
    candidates = allMedia;
  }

  // Send 2 photos
  const shuffled = candidates.sort(() => Math.random() - 0.5);
  const toSend = shuffled.slice(0, 2);
  const sentPhotos = [];

  for (const photo of toSend) {
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url: 'http://n8n_evolution-api:8080/message/sendMedia/Mih',
        headers: {
          'apikey': '429683C4C977415CAAFCCE10F7D57E11',
          'Content-Type': 'application/json'
        },
        body: {
          number: data.phone,
          mediatype: 'image',
          media: photo.url,
          caption: photo.caption || 'Resultado real - Dra. Mirian de Paula'
        },
        json: true
      });
      sentPhotos.push(photo.url);
    } catch(e) {}
  }

  // Send follow-up question AFTER the photos
  if (sentPhotos.length > 0) {
    const questions = [
      'Voce se imagina com esse tipo de resultado?',
      'Lindo ne? E o que voce esta procurando?',
      'O que acha desse tipo de transformacao?',
      'Um resultado assim e o que voce busca?'
    ];
    const q = questions[Math.floor(Math.random() * questions.length)];
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url: 'http://n8n_evolution-api:8080/message/sendText/Mih',
        headers: {
          'apikey': '429683C4C977415CAAFCCE10F7D57E11',
          'Content-Type': 'application/json'
        },
        body: { number: data.phone, text: q },
        json: true
      });
    } catch(e) {}
  }

  return [{ json: { photoSent: true, photoCount: sentPhotos.length, queixa: photoQueixa } }];
} catch(e) {
  return [{ json: { photoSent: false, queixa: photoQueixa, error: e.message } }];
}

// Merge guard result with lead context
const guard = $input.first().json;
const ctx = $('Download Media').first().json;

return [{ json: { ...ctx, guard_action: guard.action, guard_blocks: guard.blocks, guard_flags: guard.flags, guard_msgs_today: guard.msgs_today } }];
